-- FTI CONNECT 2026 sample event (from Agenda Planner sheet)
insert into public.seminar_events (
  seed_key, title, event_type, start_date, end_date, venue, event_format, owner, status, notes, is_archived
) values (
  'event:fti-connect-2026', 'FTI CONNECT 2026', 'สัมมนา / อีเวนต์', '2026-09-07', '2026-09-07', 'FTI', 'on_site', 'ทีมการตลาด', 'planning', '', false
) on conflict (seed_key) do nothing;

insert into public.seminar_event_target_groups (event_id, target_group_id)
select e.id, tg.id
from public.seminar_events e
cross join public.seminar_lib_target_groups tg
where e.seed_key = 'event:fti-connect-2026'
  and tg.name = 'Dealer ทั่วไป'
  and not exists (
    select 1 from public.seminar_event_target_groups x
    where x.event_id = e.id and x.target_group_id = tg.id
  );

insert into public.seminar_event_purposes (event_id, purpose_id)
select e.id, p.id
from public.seminar_events e
cross join public.seminar_lib_purposes p
where e.seed_key = 'event:fti-connect-2026'
  and p.name = 'อัปเดตทิศทาง FTI'
  and not exists (
    select 1 from public.seminar_event_purposes x
    where x.event_id = e.id and x.purpose_id = p.id
  );

