  'agenda:fti-connect-2026:1', e.id, 1, 'Registration', 'Logistics', 'Break', '2026-09-07', '15:42', '16:12', 30, 'ทีม Marketing Content', 'Confirmed', '[{"id":"b1","text":"ลงทะเบียน รับป้ายชื่อ เอกสาร และจัดกลุ่มผู้ร่วมงาน","sort_order":0}]'::jsonb, '[{"id":"b1","text":"เริ่มงานเป็นระบบและเก็บข้อมูลผู้เข้าร่วม","sort_order":0}]'::jsonb, '[{"id":"b1","text":"รายชื่อผู้เข้าร่วมจริงและกลุ่มเป้าหมาย","sort_order":0}]'::jsonb, array['Mixed Audience']::text[], 'ลงทะเบียน + แจก QR/เอกสาร/แผนผังโซน', ''
